/**
 * Client portal chat — uses shared API client.
 */
import { createClientChatService } from '@cagupta/shared-services';
import { apiClient } from '../../../adapters/apiClient';

const chat = createClientChatService(apiClient);

export async function fetchClientChatThread(opts = {}) {
  return chat.fetchThread(opts);
}

export async function sendClientChatMessage(bodyText) {
  return chat.sendMessage(bodyText);
}

export async function markClientChatRead(messageId) {
  return chat.markRead(messageId);
}
